1	// Apify client wrapper for Marketify edge functions.
2	//
3	// Contract: runTikTokProfile(handle, { waitSecs? })    -> { runId, datasetId, status }
4	//           runInstagramDetails(handle, { waitSecs? }) -> { runId, datasetId, status }
5	//           runInstagramPosts(handle, { waitSecs? })   -> { runId, datasetId, status }
6	// Actors:   `clockworks/tiktok-scraper` (REST slug `clockworks~tiktok-scraper`),
7	//           `apify/instagram-scraper`  (REST slug `apify~instagram-scraper`).
8	//           Actor input shapes per docs/tech-architecture.md §3b / §3c.
9	// Endpoint: POST https://api.apify.com/v2/acts/<slug>/runs?token=<key>&waitForFinish=<secs>.
10	//           The waitForFinish query parameter makes Apify block up to `waitSecs`
11	//           seconds before returning the run object, so callers can either parse
12	//           results inline (status=SUCCEEDED) or fall back to webhook-completed
13	//           delivery when the wait expires (status=RUNNING).
14	// Secret:   APIFY_KEY env var (the Apify API token).
15	// Auth:     no inbound auth requirement — this module is a building block for
16	//           edge functions that have already verified JWT.
17	
18	const APIFY_API_BASE = "https://api.apify.com/v2";
19	
20	const TIKTOK_ACTOR_SLUG = "clockworks~tiktok-scraper";
21	const INSTAGRAM_ACTOR_SLUG = "apify~instagram-scraper";
22	
23	const DEFAULT_WAIT_SECS = 60;
24	
25	export interface ApifyRunResult {
26	  runId: string;
27	  datasetId: string;
28	  status: string;
29	}
30	
31	export interface ApifyRunOptions {
32	  waitSecs?: number;
33	}
34	
35	function readApifyKey(): string {
36	  const k = Deno.env.get("APIFY_KEY");
37	  if (!k) throw new Error("APIFY_KEY is not set");
38	  return k;
39	}
40	
41	async function startActorRun(
42	  slug: string,
43	  input: Record<string, unknown>,
44	  waitSecs: number,
45	): Promise<ApifyRunResult> {
46	  if (!Number.isFinite(waitSecs) || waitSecs < 0) {
47	    throw new Error("waitSecs must be a non-negative finite number");
48	  }
49	  const url = new URL(`${APIFY_API_BASE}/acts/${slug}/runs`);
50	  url.searchParams.set("token", readApifyKey());
51	  url.searchParams.set("waitForFinish", String(Math.floor(waitSecs)));
52	
53	  const res = await fetch(url.toString(), {
54	    method: "POST",
55	    headers: { "content-type": "application/json" },
56	    body: JSON.stringify(input),
57	  });
58	
59	  if (!res.ok) {
60	    // Response body is intentionally not included — Apify sometimes echoes
61	    // the request URL (which carries the APIFY_KEY query param) inside error
62	    // payloads, and this error will land in edge-function logs.
63	    throw new Error(
64	      `Apify actor '${slug}' run failed: ${res.status} ${res.statusText}`,
65	    );
66	  }
67	
68	  const payload = (await res.json()) as {
69	    data?: { id?: string; defaultDatasetId?: string; status?: string };
70	  };
71	  const data = payload.data;
72	  if (
73	    !data ||
74	    typeof data.id !== "string" ||
75	    typeof data.defaultDatasetId !== "string" ||
76	    typeof data.status !== "string"
77	  ) {
78	    throw new Error(
79	      `Apify actor '${slug}' returned malformed run payload`,
80	    );
81	  }
82	  return {
83	    runId: data.id,
84	    datasetId: data.defaultDatasetId,
85	    status: data.status,
86	  };
87	}
88	
89	export async function runTikTokProfile(
90	  handle: string,
91	  options: ApifyRunOptions = {},
92	): Promise<ApifyRunResult> {
93	  if (!handle) throw new Error("handle is required");
94	  return await startActorRun(
95	    TIKTOK_ACTOR_SLUG,
96	    {
97	      profiles: [handle],
98	      resultsPerPage: 10,
99	      profileScrapeSections: ["videos"],
100	      profileSorting: "latest",
101	      excludePinnedPosts: true,
102	      shouldDownloadVideos: false,
103	      shouldDownloadCovers: false,
104	    },
105	    options.waitSecs ?? DEFAULT_WAIT_SECS,
106	  );
107	}
108	
109	export async function runInstagramDetails(
110	  handle: string,
111	  options: ApifyRunOptions = {},
112	): Promise<ApifyRunResult> {
113	  if (!handle) throw new Error("handle is required");
114	  return await startActorRun(
115	    INSTAGRAM_ACTOR_SLUG,
116	    {
117	      directUrls: [`https://www.instagram.com/${handle}/`],
118	      resultsType: "details",
119	      resultsLimit: 1,
120	      addParentData: false,
121	    },
122	    options.waitSecs ?? DEFAULT_WAIT_SECS,
123	  );
124	}
125	
126	export async function runInstagramPosts(
127	  handle: string,
128	  options: ApifyRunOptions = {},
129	): Promise<ApifyRunResult> {
130	  if (!handle) throw new Error("handle is required");
131	  return await startActorRun(
132	    INSTAGRAM_ACTOR_SLUG,
133	    {
134	      directUrls: [`https://www.instagram.com/${handle}/`],
135	      resultsType: "posts",
136	      resultsLimit: 10,
137	      addParentData: false,
138	    },
139	    options.waitSecs ?? DEFAULT_WAIT_SECS,
140	  );
